--
-- Table structure for table `tbl_dispatch_logs`
--

CREATE TABLE `tbl_dispatch_logs` (
  `log_id` int(11) NOT NULL,
  `incident_id` int(11) DEFAULT NULL,
  `dispatcher_id` int(11) DEFAULT NULL,
  `responder_id` int(11) DEFAULT NULL,
  `action` varchar(100) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Table structure for table `tbl_incidents`
--

CREATE TABLE `tbl_incidents` (
  `incident_id` int(11) NOT NULL,
  `tracking_id` varchar(20) DEFAULT NULL,
  `incident_type` varchar(100) DEFAULT NULL,
  `severity` enum('Moderate','High','Critical','Dead') DEFAULT 'Moderate',
  `location_lat` decimal(10,8) DEFAULT NULL,
  `location_lng` decimal(11,8) DEFAULT NULL,
  `location_address` text DEFAULT NULL,
  `incident_date` date DEFAULT NULL,
  `incident_time` time DEFAULT NULL,
  `reporter_phone` varchar(20) DEFAULT NULL,
  `reporter_name` varchar(100) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `photo_path` varchar(255) DEFAULT NULL,
  `status` enum('pending','verified','dispatched','on_scene','completed','cancelled') DEFAULT 'pending',
  `assigned_responder_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `taken_by_responder_id` int(11) DEFAULT NULL,
  `taken_at` timestamp NULL DEFAULT NULL,
  `finished_by_responder_id` int(11) DEFAULT NULL,
  `media_files` text DEFAULT NULL,
  `finished_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

